  1	import { type FC, type FormEvent, useEffect, useReducer } from 'react';
  2	import { updateNetworkMapDestination } from 'src/modules/NetworkMaps/utils/helpers/updateNetworkMapDestination';
  3	import { useForkliftTranslation } from 'src/utils/i18n';
  4	
  5	import LoadingSuspend from '@components/LoadingSuspend';
  6	import {
  7	  NetworkMapModel,
  8	  ProviderModelGroupVersionKind,
  9	  type V1beta1NetworkMap,
 10	  type V1beta1Provider,
 11	} from '@kubev2v/types';
 12	import { k8sUpdate, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 13	import {
 14	  Button,
 15	  ButtonVariant,
 16	  DescriptionList,
 17	  Flex,
 18	  FlexItem,
 19	  Spinner,
 20	} from '@patternfly/react-core';
 21	
 22	import { ProvidersEdit } from './components/ProvidersEdit';
 23	import { providersSectionReducer, type ProvidersSectionState } from './state/reducer';
 24	
 25	const initialState: ProvidersSectionState = {
 26	  hasChanges: false,
 27	  networkMap: null,
 28	  sourceProviderMode: 'view',
 29	  targetProviderMode: 'view',
 30	  updating: false,
 31	};
 32	
 33	export const ProvidersSection: FC<ProvidersSectionProps> = ({ obj }) => {
 34	  const { t } = useForkliftTranslation();
 35	  const [state, dispatch] = useReducer(providersSectionReducer, initialState);
 36	
 37	  // Initialize the state with the prop obj
 38	  useEffect(() => {
 39	    dispatch({ payload: obj, type: 'INIT' });
 40	  }, [obj]);
 41	
 42	  const [providers, providersLoaded, providersLoadError] = useK8sWatchResource<V1beta1Provider[]>({
 43	    groupVersionKind: ProviderModelGroupVersionKind,
 44	    isList: true,
 45	    namespace: obj.metadata?.namespace,
 46	    namespaced: true,
 47	  });
 48	
 49	  const targetProviders = providers.filter(
 50	    (provider) => provider?.spec?.type && ['openshift'].includes(provider.spec.type),
 51	  );
 52	
 53	  const onUpdate = async () => {
 54	    if (state.networkMap) {
 55	      dispatch({ payload: true, type: 'SET_UPDATING' });
 56	      await k8sUpdate({
 57	        data: updateNetworkMapDestination(state.networkMap),
 58	        model: NetworkMapModel,
 59	      });
 60	    }
 61	  };
 62	
 63	  const onClick = () => {
 64	    dispatch({ payload: obj, type: 'INIT' });
 65	  };
 66	
 67	  const onChangeSource: (value: string, event: FormEvent<HTMLSelectElement>) => void = (value) => {
 68	    const payload = providers.find((provider) => provider?.metadata?.name === value);
 69	    if (payload) {
 70	      dispatch({ payload, type: 'SET_SOURCE_PROVIDER' });
 71	    }
 72	  };
 73	
 74	  const onChangeTarget: (value: string, event: FormEvent<HTMLSelectElement>) => void = (value) => {
 75	    const payload = providers.find((provider) => provider?.metadata?.name === value);
 76	    if (payload) {
 77	      dispatch({ payload, type: 'SET_TARGET_PROVIDER' });
 78	    }
 79	  };
 80	
 81	  return (
 82	    <LoadingSuspend obj={providers} loaded={providersLoaded} loadError={providersLoadError}>
 83	      <Flex className="forklift-network-map__details-tab--update-button">
 84	        <FlexItem>
 85	          <Button
 86	            variant={ButtonVariant.primary}
 87	            onClick={onUpdate}
 88	            isDisabled={!state.hasChanges || state.updating}
 89	            icon={state.updating ? <Spinner size="sm" /> : undefined}
 90	          >
 91	            {t('Update providers')}
 92	          </Button>
 93	        </FlexItem>
 94	
 95	        <FlexItem>
 96	          <Button
 97	            variant={ButtonVariant.secondary}
 98	            onClick={onClick}
 99	            isDisabled={!state.hasChanges || state.updating}
100	          >
101	            {t('Cancel')}
102	          </Button>
103	        </FlexItem>
104	      </Flex>
105	
106	      <DescriptionList
107	        className="pf-v6-u-mt-md"
108	        columnModifier={{
109	          default: '1Col',
110	        }}
111	      >
112	        <ProvidersEdit
113	          providers={providers}
114	          selectedProviderName={state.networkMap?.spec?.provider?.source?.name ?? ''}
115	          label={t('Source provider')}
116	          placeHolderLabel={t('Select a provider')}
117	          onChange={onChangeSource}
118	          invalidLabel={t('The chosen provider is no longer available.')}
119	          mode={state.sourceProviderMode}
120	          helpContent="source provider"
121	          setMode={() => {
122	            dispatch({ payload: 'edit', type: 'SET_SOURCE_PROVIDER_MODE' });
123	          }}
124	        />
125	
126	        <ProvidersEdit
127	          providers={targetProviders}
128	          selectedProviderName={state.networkMap?.spec?.provider?.destination?.name ?? ''}
129	          label={t('Target provider')}
130	          placeHolderLabel={t('Select a provider')}
131	          onChange={onChangeTarget}
132	          invalidLabel={t('The chosen provider is no longer available.')}
133	          mode={state.targetProviderMode}
134	          helpContent="Target provider"
135	          setMode={() => {
136	            dispatch({ payload: 'edit', type: 'SET_TARGET_PROVIDER_MODE' });
137	          }}
138	        />
139	      </DescriptionList>
140	    </LoadingSuspend>
141	  );
142	};
143	
144	type ProvidersSectionProps = {
145	  obj: V1beta1NetworkMap;
146	};

